using UnityEngine;
public class Script
{
    public static object Main()
    {
        try
        {
            var result = "";
            var allGOs = Object.FindObjectsOfType<GameObject>();
            int vehicleCount = 0;
            foreach (var go in allGOs)
            {
                if (go.name.ToLower().Contains("vehicle") || go.name.ToLower().Contains("car") || go.name.ToLower().Contains("traffic"))
                {
                    if (vehicleCount < 10)
                        result += go.name + " parent=" + (go.transform.parent ? go.transform.parent.name : "root") + " pos=" + go.transform.position + "\n";
                    vehicleCount++;
                }
            }
            result += "Total vehicle/car/traffic GOs: " + vehicleCount;
            return result;
        }
        catch (System.Exception ex) { return "Error: " + ex.Message; }
    }
}
